          i++
        }
        continue
      }

      // Validate the flag
      const error = validateFlag(arg, schema)
      if (error) {
        return { argv, error }
      }

      // It's a valid flag
      if (arg.includes('=')) {
        // --flag=value syntax, keep as single arg
        flags.push(arg)
        i++
      } else if (schemaFlagTakesValue(schema, arg)) {
        // Flag with separate value
